mapper.select:
SELECT id, `year_month`, supplier_name, category, total, grade, dimension_a, dimension_b, dimension_c, dimension_d, sub_a1, sub_a2, sub_a3, sub_a4, sub_b1, sub_b2, sub_b3, sub_b4, sub_b5, sub_c1, sub_c2, sub_c3, sub_d1a, sub_d1b, sub_d2a, sub_d2b, sub_d2c, sub_d2d, sub_d2e, conclusion, exception_quality, exception_cost, exception_delivery, exception_service_product, exception_service_package, exception_other, status, file_name, is_deleted, create_name, create_id, create_date, update_name, update_id, update_date FROM sp_monthly_assessment WHERE is_deleted = 0
AND `year_month` = #{yearMonth}
AND supplier_name LIKE CONCAT('%', #{supplierName}, '%')
AND category = #{category}
AND grade = #{grade}
AND status = #{status}
ORDER BY `year_month` DESC, create_date DESC

mapper.update:
UPDATE sp_monthly_assessment
`year_month` = #{yearMonth}, supplier_name = #{supplierName}, category = #{category}, total = #{total}, grade = #{grade}, dimension_a = #{dimensionA}, dimension_b = #{dimensionB}, dimension_c = #{dimensionC}, dimension_d = #{dimensionD}, conclusion = #{conclusion}, status = #{status}, file_name = #{fileName}, update_name = #{updateName}, update_id = #{updateId},
WHERE id = #{id}
